+        let file_len = std::fs::metadata(&self.data_path)
+            .map(|m| m.len())
+            .unwrap_or(0);
+        if file_len == 0 {
+            return Ok(RecorderOffset {
+                segment_id: 0,
+                byte_offset: 0,
+                ordinal: 0,
+            });
+        }
+        let mut reader = AppendLogReader::open(&self.data_path)
+            .map_err(|e| EventCursorError::Io(e.to_string()))?;
